import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All"); // "All", "Running", "Ghost"

  useEffect(() => {
    const ws = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        setBuses(data.buses || []);
      } catch (err) {
        console.error("Failed to parse WS message:", err);
      }
    };

    ws.onopen = () => console.log("[WS] Connected");
    ws.onclose = () => console.log("[WS] Disconnected");

    return () => ws.close();
  }, []);

  // Filter buses based on selected filter
  const filteredBuses = buses.filter((bus) => {
    if (filter === "All") return true;
    if (filter === "Running") return bus.status === "Running";
    if (filter === "Ghost") return bus.status !== "Running";
    return true;
  });

  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status !== "Running").length;

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Filter buttons at top-left */}
      <div
        style={{
          position: "absolute",
          top: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        <button onClick={() => setFilter("All")} style={{ marginRight: 5 }}>
          All
        </button>
        <button onClick={() => setFilter("Running")} style={{ marginRight: 5 }}>
          Running
        </button>
        <button onClick={() => setFilter("Ghost")}>Ghost</button>
      </div>

      {/* Bus counters at bottom-left */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount}
      </div>

      <MapContainer
        center={[40.7128, -74.006]} // NYC center
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus) => (
          <CircleMarker
            key={`${bus.id}-${bus.source}`} // unique key
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={bus.status === "Running" ? "green" : "red"}
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Route:</strong> {bus.route} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong> {bus.speed?.toFixed(1)} mph <br />
                <strong>Source:</strong> {bus.source}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
